mapper.select:
SELECT m.*, u.real_name as target_user_name
FROM message m
LEFT JOIN user u ON m.target_user_id = u.id

    
        AND m.target_role = #{targetRole}
    
    
        AND m.target_user_id = #{targetUserId}
    
    
        AND m.is_read = #{isRead}
    

ORDER BY m.create_time DESC
